-- Create "payload_property_definitions" table
CREATE TABLE "payload_property_definitions" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "payload_type" character varying NOT NULL,
  "key" character varying NOT NULL,
  "value_type" character varying NOT NULL,
  "default_value" jsonb NULL,
  "enum_values" jsonb NULL,
  "description" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "deleted_at" timestamptz NULL,
  PRIMARY KEY ("id")
);
-- Create index "payloadpropertydefinition_payload_type_key" to table: "payload_property_definitions"
CREATE UNIQUE INDEX "payloadpropertydefinition_payload_type_key" ON "payload_property_definitions" ("payload_type", "key");
-- Create "users" table
CREATE TABLE "users" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "username" character varying NOT NULL,
  "email" character varying NOT NULL,
  "password" character varying NOT NULL,
  "role" character varying NOT NULL DEFAULT 'USER',
  "status" character varying NOT NULL DEFAULT 'ACTIVE',
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "deleted_at" timestamptz NULL,
  PRIMARY KEY ("id")
);
-- Create index "users_email_key" to table: "users"
CREATE UNIQUE INDEX "users_email_key" ON "users" ("email");
-- Create index "users_username_key" to table: "users"
CREATE UNIQUE INDEX "users_username_key" ON "users" ("username");
-- Create "mobile_configs" table
CREATE TABLE "mobile_configs" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "name" character varying NOT NULL,
  "payload_identifier" character varying NOT NULL,
  "payload_type" character varying NOT NULL,
  "payload_display_name" character varying NOT NULL,
  "payload_description" character varying NULL,
  "payload_organization" character varying NULL,
  "payload_uuid" character varying NOT NULL,
  "payload_version" bigint NOT NULL DEFAULT 1,
  "payload_removal_disallowed" boolean NOT NULL DEFAULT false,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "deleted_at" timestamptz NULL,
  PRIMARY KEY ("id")
);
-- Create index "mobile_configs_name_key" to table: "mobile_configs"
CREATE UNIQUE INDEX "mobile_configs_name_key" ON "mobile_configs" ("name");
-- Create index "mobile_configs_payload_identifier_key" to table: "mobile_configs"
CREATE UNIQUE INDEX "mobile_configs_payload_identifier_key" ON "mobile_configs" ("payload_identifier");
-- Create index "mobileconfig_payload_identifier" to table: "mobile_configs"
CREATE UNIQUE INDEX "mobileconfig_payload_identifier" ON "mobile_configs" ("payload_identifier");
-- Create "payloads" table
CREATE TABLE "payloads" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "payload_description" character varying NULL,
  "payload_display_name" character varying NOT NULL,
  "payload_identifier" character varying NOT NULL,
  "payload_organization" character varying NULL,
  "payload_type" character varying NOT NULL,
  "payload_uuid" character varying NOT NULL,
  "payload_version" bigint NOT NULL DEFAULT 1,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "deleted_at" timestamptz NULL,
  "mobile_config_payloads" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "payloads_mobile_configs_payloads" FOREIGN KEY ("mobile_config_payloads") REFERENCES "mobile_configs" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION
);
-- Create index "payloads_payload_identifier_key" to table: "payloads"
CREATE UNIQUE INDEX "payloads_payload_identifier_key" ON "payloads" ("payload_identifier");
-- Create "payload_properties" table
CREATE TABLE "payload_properties" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "value_json" jsonb NULL,
  "value_type" character varying NOT NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "deleted_at" timestamptz NULL,
  "payload_properties" bigint NOT NULL,
  "payload_property_definition_properties" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "payload_properties_payload_property_definitions_properties" FOREIGN KEY ("payload_property_definition_properties") REFERENCES "payload_property_definitions" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "payload_properties_payloads_properties" FOREIGN KEY ("payload_properties") REFERENCES "payloads" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION
);
